  if (taskfile?.match(/^\s{2,}ci:/m)) return { commands: ["task ci"], evidence: ["Taskfile ci task"], warnings: [] as string[] };
  const scripts = packageJson?.scripts ?? {}; const runner = String(packageJson?.packageManager ?? "").startsWith("pnpm@") ? "pnpm" : "npm run"; if (typeof scripts.ci === "string") return { commands: [`${runner} ci`], evidence: ["package.json ci script"], warnings: [] as string[] };
