function startPoint(source: string, defaultBranch: string) { return git(source, ["rev-parse", "--verify", `${defaultBranch}^{commit}`]) ? defaultBranch : git(source, ["rev-parse", "--verify", `origin/${defaultBranch}^{commit}`]) ? `origin/${defaultBranch}` : undefined; }
type LifecycleEnvironment = { baseWorkspace: string; baseProject?: string };
