function models() { try { return execFileSync("pi", ["--list-models"], { encoding: "utf8" }).split("\n").slice(1).map((line) => line.trim().split(/\s+/)).filter((part) => part.length >= 2).map((part) => `${part[0]}/${part[1]}`); } catch { return []; } }
