async function entries(dir: string) { const files = await readdir(dir, { withFileTypes: true }).catch(() => []); const all = await Promise.all(files.map(async (file) => { const target = path.join(dir, file.name); return file.isDirectory() ? entries(target) : file.isFile() && file.name.endsWith(".md") ? [target] : []; })); return all.flat(); }
function knowledgePath(root: string, docs: string, entryPath: string) { const target = path.resolve(root, entryPath); const base = path.resolve(root, docs); if (!inside(base, target)) throw new Error("Knowledge entry path escapes docs/."); return target; }
function validateKnowledge(kind: string, title: string, body: string) { if (!KINDS[kind]) throw new Error("Unknown knowledge kind."); if (!title.trim() || !body.includes(`# ${title.trim()}`)) throw new Error("Knowledge must contain an H1 matching title."); for (const heading of KINDS[kind]) if (!body.includes(`## ${heading}`)) throw new Error(`Knowledge is missing required section: ${heading}`); }
function sectionPatch(body: string, section: string, expected: string, next: string) { const heading = new RegExp(`^## ${section.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\r?\\n`, "m"); const match = heading.exec(body); if (!match || match.index === undefined) throw new Error(`Section not found: ${section}`); const start = match.index + match[0].length; const following = /^## .+$/gm; following.lastIndex = start; const nextHeading = following.exec(body); const end = nextHeading?.index ?? body.length; const current = body.slice(start, end); if (current.trim() !== expected.trim()) throw new Error(`Section changed since it was read: ${section}.`); if (normal(current) === normal(next)) return { body, changed: false }; return { body: `${body.slice(0, start)}${next.trim()}\n\n${body.slice(end)}`, changed: true }; }
function normalizedSection(value: string) { return value.toLowerCase().replace(/[^a-z0-9]+/g, "").trim(); }
function cleanSection(value: string) { const section = value.replace(/[\r\n#]+/g, " ").trim(); if (!section) throw new Error("Knowledge section names cannot be empty."); return section; }
function canonicalKind(kind: string) { const cleaned = cleanSection(kind); return Object.keys(KINDS).find((candidate) => normalizedSection(candidate) === normalizedSection(cleaned)) ?? cleaned; }
function kindDirectory(kind: string) { return canonicalKind(kind).toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "") || "reference"; }
function canonicalSection(kind: string, section: string) { const cleaned = cleanSection(section); return KINDS[canonicalKind(kind)]?.find((candidate) => normalizedSection(candidate) === normalizedSection(cleaned)) ?? cleaned; }
function emptyKnowledgeEntry(kind: string, title: string, sections: Record<string, string>) { const canonical = canonicalKind(kind); const supplied = Object.entries(sections).map(([section, content]) => [canonicalSection(canonical, section), content] as const); const required = KINDS[canonical]; if (!required) return `# ${title.trim()}\n\n${supplied.map(([section, content]) => `## ${section}\n\n${content.trim()}`).join("\n\n")}\n`; const known = new Map(supplied.filter(([section]) => required.includes(section))); const extra = supplied.filter(([section]) => !required.includes(section)); const body = `# ${title.trim()}\n\n${required.map((section) => `## ${section}\n\n${known.get(section)?.trim() ?? ""}`).join("\n\n")}${extra.length ? `\n\n${extra.map(([section, content]) => `## ${section}\n\n${content.trim()}`).join("\n\n")}` : ""}\n`; validateKnowledge(canonical, title, body); return body; }
function replaceKnowledgeSection(body: string, section: string, next: string) { const requested = cleanSection(section); const headings = [...body.matchAll(/^## (.+)$/gm)]; const found = headings.find((heading) => normalizedSection(heading[1]!) === normalizedSection(requested)); if (!found || found.index === undefined) { if (!next.trim()) return { body, changed: false }; return { body: `${body.trimEnd()}\n\n## ${requested}\n\n${next.trim()}\n`, changed: true }; } const start = found.index + found[0].length + 1; const nextHeading = headings.find((heading) => (heading.index ?? 0) > found.index!); const end = nextHeading?.index ?? body.length; const current = body.slice(start, end); if (normal(current) === normal(next)) return { body, changed: false }; return { body: `${body.slice(0, start)}\n${next.trim()}\n\n${body.slice(end)}`, changed: true }; }

export default function workspaceFlow(pi: ExtensionAPI) {
  const rootFor = (ctx: ExtensionContext) => findRoot(ctx.cwd); const approvals = new Set<string>();
  pi.registerMessageRenderer?.("subagent_supervisor_request", (message: any, { expanded }: { expanded: boolean }, theme: any) => { if (supervisorOutput() === "full") return new Text(String(message.content)); const details = message.details as { reason?: string; agent?: string; runId?: string; childIndex?: number } | undefined; const body = String(message.content).split(/\n\s*\n/).slice(-1)[0]?.trim() || "No details supplied."; const label = details?.reason === "need_decision" ? "needs a decision" : details?.reason === "interview_request" ? "requests input" : "update"; const title = `${details?.agent ?? "subagent"} ${label}: ${body}`; const meta = `run ${details?.runId ?? "unknown"}, child ${details?.childIndex ?? "?"}`; return new Text(expanded ? `${title}\n${theme.fg("dim", meta)}` : title); });
  pi.events?.on?.("ask:answered", (raw) => { const value = raw as any; const token = value.context?.match(/pi-harness:onboarding-apply:([a-f0-9]{24})/)?.[1]; if (token && value.response?.kind === "selection" && value.response.selections?.includes("Apply now")) approvals.add(token); });
  const send = (text: string) => pi.sendUserMessage(text, { deliverAs: "followUp" });
  pi.registerCommand("workspace:sync", { description: "Synchronize generated settings from workspace.yaml", handler: async (_args, ctx) => { const v = await sync(rootFor(ctx)); ctx.ui.notify(`Synced pi-harness ${v}.`, "info"); } });
  pi.registerCommand("workspace:onboard", { description: "Analyze local projects and guide workspace configuration", handler: async (args, ctx) => { if (isSubagent()) throw new Error("Only the orchestrator may onboard."); if (args.trim()) throw new Error("Onboarding takes no sources. Set up repositories under projects/ first."); await send("Start local-first workspace onboarding. Load workspace-onboarding and ask-user skills. Call workspace_onboarding action=discover with no source arguments. Analyze only local projects/*; never call GitHub, web, gh, or remote inspection. Use ask_user to confirm CI for each included project, dependency relationships, model pins, and the setup/cleanup commands for workspace sessions; do not infer those preferences. Ask one focused decision at a time. Present the complete workspace.yaml, including workspace.setup, workspace.cleanup, and each project setup/cleanup array, immediately stage that exact proposal with workspace_onboarding action=propose, then ask the single final token-bound Apply now / Revise proposal / Cancel question. Never ask any earlier approval question, and never create or clone repositories during onboarding."); } });
  pi.registerCommand("workspace:session", { description: "Create or clean up an isolated, reattachable workspace session", handler: async (args, ctx) => { if (isSubagent()) throw new Error("Only the orchestrator may manage a workspace session."); const root = rootFor(ctx); const [action, ...rest] = args.trim().split(/\s+/); if (action === "cleanup") { const removed = await cleanupSessionWorktree(root, rest.join(" ")); await send(`Cleaned up session worktree ${path.relative(root, removed.target)}.`); return; } const created = await createSessionWorktree(root, sessionId(ctx), args); await send(`Workspace session created at ${path.relative(root, created.target)} on ${created.branch}. Setup hooks ran directly in the extension with their worktree as $PWD; PH_WORKSPACE_BASE points to this primary root and project hooks also receive PH_PROJECT_BASE. Open Pi in the new directory, then run /workspace:continue ${created.state.id} to reattach the saved workflow.`); } });
  pi.registerCommand("workspace:plan", { description: "Start user-controlled planning", handler: async (subject, ctx) => { const root = rootFor(ctx); const owner = sessionId(ctx); if (await loadState(root, owner)) throw new Error("This session already owns a workflow."); const state = createWorkflow(subject, owner); await saveState(root, state); pi.setSessionName(state.subject); await send(`The workflow is in plan phase. Immediately load workspace-development-loop and workspace-knowledge-protocol; they are the workflow authority—never inspect node_modules, .pi internals, or package source to rediscover this workflow. Required order: (1) call workspace_knowledge orientation, then search/read relevant project architecture, contracts, decisions, and subject context; (2) inspect the available codebase-memory MCP tools and use the graph for structural discovery; (3) use targeted direct reads only for code facts not answered by knowledge or graph. After that evidence, choose a concise semantic branch name: an appropriate work-type prefix (for example feat, fix, docs, refactor, test, ci, build, chore, perf, or style) plus the shortest clear description of the actual outcome. This may mirror Conventional Commit types, but branch naming is a Harness convention, not the Conventional Commits specification. Do not mechanically slug the user’s request; name the actual outcome. Before any knowledge write, create and record that branch in the coordination root and each affected product. The fallback suggestion is ${branchName(state.subject)}, but replace it whenever the evidence supports a clearer name. Do not replace unfamiliar structural exploration with broad parent file reading: launch the named explore agent via subagent (never generic delegate), async:true, clarify:false, context:fresh, artifacts:false, acceptance:{level:none,reason:"Pi Harness owns worker evidence, CI, and review."}, and with no cwd override, for every task that is not narrow and graph-known. Skip explore only when the graph and handoff already answer the narrow question. Parent may read non-doc workspace/project files and create suggested branches, but must never edit product files; docs are only through workspace_knowledge. Create durable Plan and Task entries with workspace_knowledge_record, and create/update a Reference titled Project architecture — <project> for every affected project: purpose, ownership, entry points, key modules, flows, interfaces, configuration, validation, and graph anchors. Record factual sections in natural names, never a hand-formatted Markdown body; matching headings update and new factual headings are added, preserving everything else.`); } });
  pi.registerCommand("workspace:code", { description: "User-authorize plan/review to code", handler: async (feedback, ctx) => { const root = rootFor(ctx); const state = await loadState(root, sessionId(ctx)); if (!state) throw new Error("No active workflow."); await saveState(root, transition(state, "code")); await send(`The workflow is now in code. Delegate every product edit with the pi-subagents subagent tool. Route a one-file documentation, test, config, or localized implementation change to impl-lite; use impl only for multi-file, cross-project, contract, or genuinely complex work. Never use generic delegate, an intercom-only child, or foreground parallel execution. Launch async:true, clarify:false, context:fresh, artifacts:false, acceptance:{level:none,reason:"Pi Harness owns worker evidence, CI, and review."}, and NO cwd override so child Pi loads this session workspace's tools. State the target checkout path in the handoff and have the worker operate beneath projects/. Include acceptance criteria, graph evidence, and configured CI, but never tell workers to read canonical docs or call workspace knowledge. One writer per checkout at a time; each workspace session owns a separate product checkout. Continue independent orchestration work; when waiting is necessary, use wait rather than status-polling. The resolved workspace.yaml model pins for impl and impl-lite apply to those exact agent names. ${feedback.trim() ? `Address: ${feedback.trim()}` : "Implement the approved plan."} Before review, record material architecture/contract/decision outcomes, commit tracked coordination changes on the workspace branch, and create/record a workspace PR if its GitHub origin has usable gh access. Collect concise structured handoffs, run configured CI, update canonical knowledge, push branches and create PRs only where available, then record evidence and enter review.`); } });
  pi.registerCommand("workspace:done", { description: "User-authorize review closure", handler: async (_args, ctx) => { const root = rootFor(ctx); const state = await loadState(root, sessionId(ctx)); if (!state) throw new Error("No active workflow."); await saveState(root, transition(state, "done")); await send("The workflow is done. Do not edit, merge, create PRs, or write knowledge. Summarize PRs in dependency order and offer cleanup only after confirmed merges."); } });
  pi.registerCommand("workspace:status", { description: "Show workflow state", handler: async (_args, ctx) => ctx.ui.notify((await loadState(rootFor(ctx), sessionId(ctx))) ? render((await loadState(rootFor(ctx), sessionId(ctx)))!) : "No active workflow.", "info") });
  pi.registerCommand("workspace:continue", { description: "Rebind a saved workflow", handler: async (id, ctx) => { const root = rootFor(ctx); const owner = sessionId(ctx); const directory = path.join(root, FLOW_DIR, "state"); const states = await Promise.all((await readdir(directory).catch(() => [])).filter((x) => x.endsWith(".json")).map(async (x) => JSON.parse(await readFile(path.join(directory, x), "utf8")) as WorkflowState)); const state = states.find((x) => x.id.startsWith(id.trim()) || x.sessionId.startsWith(id.trim())); if (!state) throw new Error("No matching workflow."); await saveState(root, { ...state, sessionId: owner, updatedAt: new Date().toISOString() }); await rename(statePath(root, state.sessionId), `${statePath(root, state.sessionId)}.rebound`).catch(() => undefined); } });

  pi.registerTool({ name: "workspace_session", label: "Workspace Session", description: "Create, list, or safely clean up reattachable workspace sessions. Creation makes one coordination worktree and matching product worktrees, then runs configured setup commands.", parameters: Type.Object({ action: Type.Union([Type.Literal("create"), Type.Literal("list"), Type.Literal("cleanup")]), subject: Type.Optional(Type.String()), session: Type.Optional(Type.String()) }), async execute(_id, input, _signal, _update, ctx) { if (isSubagent()) throw new Error("Only the orchestrator manages workspace sessions."); const root = rootFor(ctx); const local = await settings(root); const directory = worktreeDirectory(root, local); if (input.action === "list") { const output = git(root, ["worktree", "list", "--porcelain"]) ?? ""; const sessions = output.split("\n\n").map((entry) => entry.match(/^worktree (.+)$/m)?.[1]).filter((entry): entry is string => Boolean(entry && inside(directory, entry))).map((entry) => path.relative(root, entry)); return { content: [{ type: "text", text: JSON.stringify({ directory: path.relative(root, directory), sessions }, null, 2) }], details: { directory: path.relative(root, directory), sessions } }; } if (input.action === "cleanup") { if (!input.session) throw new Error("cleanup requires a session name from workspace_session list."); const removed = await cleanupSessionWorktree(root, input.session); return { content: [{ type: "text", text: `Cleaned up session worktree ${path.relative(root, removed.target)}.` }], details: { path: path.relative(root, removed.target), removed: true } }; } if (!input.subject?.trim()) throw new Error("Creating a workspace session requires a subject."); const created = await createSessionWorktree(root, sessionId(ctx), input.subject); return { content: [{ type: "text", text: `Created session worktree at ${path.relative(root, created.target)}. Setup hooks ran directly in the extension with $PWD at the new worktree; PH_WORKSPACE_BASE points to the primary root and project hooks also receive PH_PROJECT_BASE. Open Pi there and run /workspace:continue ${created.state.id}.` }], details: { path: path.relative(root, created.target), branch: created.branch, workflowId: created.state.id, products: created.state.sessionWorktree?.products } }; } });
  pi.registerTool({ name: "workspace_workflow", label: "Workspace Workflow", description: "Read or record workflow state; review requires a committed coordination workspace, CI, graph evidence, and PRs wherever GitHub access is available.", parameters: Type.Object({ action: Type.Union([Type.Literal("status"), Type.Literal("update"), Type.Literal("record_checks"), Type.Literal("enter_review")]), projects: Type.Optional(Type.Array(Type.String())), branches: Type.Optional(Type.Record(Type.String(), Type.String())), pullRequests: Type.Optional(Type.Record(Type.String(), Type.Number())), notes: Type.Optional(Type.Array(Type.String())), ciPassed: Type.Optional(Type.Boolean()), codeIndexed: Type.Optional(Type.Boolean()) }), async execute(_id, input, _signal, _update, ctx) { const root = rootFor(ctx); const state = await loadState(root, sessionId(ctx)); if (!state) throw new Error("No active workflow."); if (input.action === "status") return { content: [{ type: "text", text: render(state) }], details: state }; if (isSubagent()) throw new Error("Only the orchestrator updates workflow state."); if (input.action === "enter_review") { if (!state.checks.ciPassed || !state.checks.codeIndexed) throw new Error("CI and code-index checks must be recorded before review."); const workspaceBranch = git(root, ["branch", "--show-current"]); if (workspaceBranch === "main") throw new Error("Commit coordination changes on their workflow branch, not main, before review."); const pendingWorkspaceChanges = git(root, ["status", "--porcelain"]); if (pendingWorkspaceChanges) throw new Error("Commit all non-ignored coordination-workspace changes before review."); const configured = (await manifest(root)).projects ?? []; const required = state.projects.filter((name) => name !== "workspace" && pullRequestAvailable(configured.find((project) => project.name === name))); if (workspacePullRequestAvailable(root)) required.unshift("workspace"); const missing = required.filter((name) => !state.pullRequests[name]); if (missing.length) throw new Error(`Open and record PRs before review. GitHub PR access is available for: ${missing.join(", ")}`); const next = transition(state, "review"); await saveState(root, next); return { content: [{ type: "text", text: render(next) }], details: { ...next, pullRequestsRequired: required } }; } if (!["plan", "code"].includes(state.phase)) throw new Error(`Cannot record workflow evidence in ${state.phase}.`); const next = { ...state, projects: input.projects ? [...new Set(["workspace", ...input.projects])] : state.projects, branches: input.branches ?? state.branches, pullRequests: input.pullRequests ?? state.pullRequests, notes: input.notes ?? state.notes, checks: { ciPassed: input.ciPassed ?? state.checks.ciPassed, codeIndexed: input.codeIndexed ?? state.checks.codeIndexed }, updatedAt: new Date().toISOString() }; await saveState(root, next); return { content: [{ type: "text", text: render(next) }], details: next }; } });
  pi.registerTool({ name: "workspace_onboarding", label: "Workspace Onboarding", description: "Analyze local projects and stage/apply a reviewed workspace manifest.", parameters: Type.Object({ action: Type.Union([Type.Literal("discover"), Type.Literal("propose"), Type.Literal("apply")]), manifest: Type.Optional(Type.String()), approvalToken: Type.Optional(Type.String()) }), async execute(_id, input, _signal, _update, ctx) { if (isSubagent()) throw new Error("Only the orchestrator may onboard."); const root = rootFor(ctx); if (input.action === "discover") { const projects = await discover(root); const available = models(); const text = onboardingManifest(await readFile(path.join(root, "workspace.yaml"), "utf8"), projects, available); return { content: [{ type: "text", text: JSON.stringify({ proposed_workspace_yaml: text, projects, available_models: available, suggested_agents: modelProposal(available) }, null, 2) }], details: { manifest: text, repositories: projects, models: available } }; } if (input.action === "propose") { if (!input.manifest?.trim()) throw new Error("propose requires complete workspace.yaml."); await stageProposal(root, input.manifest); const token = proposalToken(input.manifest); return { content: [{ type: "text", text: `Staged proposal. Ask ask_user Apply now / Revise proposal / Cancel using context pi-harness:onboarding-apply:${token}; only then call apply with approvalToken.` }], details: { approvalToken: token } }; } const proposal = JSON.parse(await readFile(path.join(root, ONBOARDING_FILE), "utf8")); const token = proposalToken(proposal.manifest); if (!input.approvalToken || input.approvalToken !== token || !approvals.delete(token)) throw new Error("Applying onboarding requires a fresh ask_user response selecting Apply now for this exact proposal."); await applyProposal(root); return { content: [{ type: "text", text: "Applied workspace onboarding proposal and synchronized generated configuration." }], details: { applied: true } }; } });
  pi.registerTool({ name: "workspace_knowledge", label: "Workspace Knowledge", description: "Orient to, search, and read canonical workspace knowledge. Begin planning with orientation; use workspace_knowledge_record for every normal write.", parameters: Type.Object({ action: Type.Union([Type.Literal("orientation"), Type.Literal("search"), Type.Literal("read")]), query: Type.Optional(Type.String()), entryPath: Type.Optional(Type.String()), projects: Type.Optional(Type.Array(Type.String())) }), async execute(_id, input, _signal, _update, ctx) { if (isSubagent()) throw new Error("Only the orchestrator may access canonical knowledge."); const root = rootFor(ctx); const local = await settings(root); const docsRoot = path.resolve(root, local.docs); const files = await entries(docsRoot); if (input.action === "orientation") { const names = (input.projects ?? []).map((project) => project.toLowerCase()); const results = await Promise.all(files.map(async (file) => ({ path: path.relative(root, file), text: await readFile(file, "utf8") }))); const selected = results.filter((entry) => { const pathName = entry.path.toLowerCase(); const durable = /\/(reference|contract|decision)\//.test(pathName); return durable && (!names.length || names.some((name) => pathName.includes(name) || entry.text.toLowerCase().includes(name))); }).map(({ path: entryPath, text }) => ({ path: entryPath, title: text.match(/^#\s+(.+)$/m)?.[1] ?? path.basename(entryPath, ".md"), excerpt: text.slice(0, 1200) })); return { content: [{ type: "text", text: JSON.stringify({ orientation: selected, guidance: "Read the relevant Project Architecture References, Contracts, and Decisions before graph or direct-code exploration." }, null, 2) }], details: { entries: selected.map((entry) => entry.path) } }; } if (input.action === "search") { const query = (input.query ?? "").toLowerCase(); const results = await Promise.all(files.map(async (file) => ({ path: path.relative(root, file), text: await readFile(file, "utf8") }))); return { content: [{ type: "text", text: JSON.stringify(results.filter((entry) => entry.text.toLowerCase().includes(query)).map(({ path: entryPath, text }) => ({ path: entryPath, excerpt: text.slice(0, 700) })), null, 2) }] }; } if (!input.entryPath) throw new Error("read requires entryPath."); const file = knowledgePath(root, local.docs, input.entryPath); return { content: [{ type: "text", text: await readFile(file, "utf8") }], details: { path: path.relative(root, file) } }; } });
  pi.registerTool({ name: "workspace_knowledge_record", label: "Record Workspace Knowledge", description: "Record factual canonical knowledge. Give a kind, title, and only the factual sections that materially changed; section names and kinds are flexible. Existing headings match case-insensitively, unnamed sections are preserved, and wording-only/format-only changes do nothing. Use only in plan or code, before entering review.", parameters: Type.Object({ kind: Type.String(), title: Type.String(), sections: Type.Record(Type.String(), Type.String()) }), async execute(_id, input, _signal, _update, ctx) { if (isSubagent()) throw new Error("Only the orchestrator may record canonical knowledge."); const root = rootFor(ctx); const state = await loadState(root, sessionId(ctx)); if (!["plan", "code"].includes(state?.phase ?? "")) throw new Error("Knowledge is frozen in review/done; record factual changes before entering review."); const local = await settings(root); if (!input.title.trim()) throw new Error("Provide a knowledge title."); if (!Object.keys(input.sections).length) throw new Error("Provide at least one factual section to record."); const file = path.join(path.resolve(root, local.docs), kindDirectory(input.kind), `${input.title.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "")}.md`); let body: string; let changed = false; let created = false; if (!existsSync(file)) { body = emptyKnowledgeEntry(input.kind, input.title, input.sections); changed = true; created = true; } else { body = await readFile(file, "utf8"); for (const [section, content] of Object.entries(input.sections)) { const patched = replaceKnowledgeSection(body, canonicalSection(input.kind, section), content); body = patched.body; changed ||= patched.changed; } } if (changed) { await mkdir(path.dirname(file), { recursive: true }); await writeFile(file, body); } return { content: [{ type: "text", text: changed ? `${created ? "Created" : "Recorded"} factual knowledge.` : "No material knowledge change; left entry untouched." }], details: { path: path.relative(root, file), created, changed, sections: Object.keys(input.sections) } }; } });
  pi.on("tool_call", async (event: any, ctx: ExtensionContext) => { const root = (() => { try { return rootFor(ctx); } catch { return null; } })(); if (!root) return; const local = await settings(root); const docsRoot = path.resolve(root, local.docs); const input = event.input ?? {}; const candidate = typeof input.path === "string" ? path.resolve(root, input.path) : null; if (event.toolName === "subagent" && !input.action && input.artifacts !== false) return { block: true, reason: "Harness subagent launches require artifacts:false so disposable files never enter product repositories." }; if (event.toolName !== "workspace_knowledge" && candidate && inside(docsRoot, candidate)) return { block: true, reason: "Canonical docs are accessible only through workspace_knowledge." }; if (event.toolName === "bash" && typeof input.command === "string" && commandReferencesDocs(input.command, root, local.docs)) return { block: true, reason: "Canonical docs are accessible only through workspace_knowledge." }; const workflow = await loadState(root, sessionId(ctx)); if (["write", "edit", "apply_patch"].includes(event.toolName) && candidate && inside(path.resolve(root, local.projects), candidate) && !isWorker()) return { block: true, reason: "The parent orchestrator never edits projects/**; delegate to impl or impl-lite." }; if (event.toolName === "bash") { const command = String(input.command ?? ""); if (command.includes(".pi/harness/state")) return { block: true, reason: "Workflow state is tool-managed." }; if (!workflow && !isReadOnlyPhaseCommand(command)) return { block: true, reason: "No active workflow: shell is read-only. Start with /workspace:plan." }; if (workflow?.phase === "plan" && !isPlanPhaseCommand(command)) return { block: true, reason: "Plan permits inspection and feat/fix branches only." }; if (workflow && ["review", "done"].includes(workflow.phase) && !isReadOnlyPhaseCommand(command)) return { block: true, reason: `Shell is read-only in ${workflow.phase}.` }; if (workflow?.phase !== "code" && /^gh\s+pr\s+create\b/.test(command)) return { block: true, reason: "PR creation is allowed only in code." }; if (/\bgit\s+push\s+.*--force\b/.test(command)) return { block: true, reason: "Force pushes are blocked." }; } });
}
